int lengthOfLIS(int* nums, int n) {
    int* tails = malloc(n * sizeof(int));
    int len = 0;
    for (int i = 0; i < n; i++) {
        int x = nums[i], l = 0, r = len;
        while (l < r) {
            int m = l + (r - l) / 2;
            if (tails[m] < x) l = m + 1;
            else r = m;
        }
        tails[l] = x;
        if (l == len) len++;
    }
    free(tails);
    return len;
}
